svg.script:
// mini-idle-engine-v1.js — 机器生成, 勿手改; 改动走 _build-mini-idle-engine-v1.py
// 来源: confirmed hamster-idle-follow-v2.svg 的内嵌引擎(逐字提取) + 3 处 mini patch(见生成器)。
// 引擎所有几何在母版坐标系内工作; mini 的整体 rotate(-90 187 230) 是外层 wrapper,
// 因此 cheek 锚点公式 / facePlane / 腮红 clip 合同 / 墨镜弹簧全部零改动复用。

(function () {
  "use strict";
  var NS = "http://www.w3.org/2000/svg";

  // ── inlined head-anchor data ──────────────────────────────────────────────
  // Result of flattenAnchors() over the confirmed V15 bf-eye-decoupled anchor
  // JSON (drafts/side-45/face-anchor-v1/confirmed-v15-bf-eye-decoupled-anchors/
  // hamster-face-anchor-v1-settings.confirmed.json). Hard-coded so the file has
  // no fetch / external dependency. Only A/L/C/D/E/R/G are read by the look
  // geometry, but the full flattened set is inlined verbatim for fidelity.
  var rawAnchors = {
    A:  { x: 65,     y: 153,    label: "左边界" },
    L:  { x: 137.77, y: 162.56, label: "左弧低点" },
    C:  { x: 171.37, y: 154.02, label: "鼻梁左" },
    D:  { x: 189.69, y: 147.65, label: "鼻梁峰" },
    E:  { x: 210.43, y: 157.48, label: "鼻梁右" },
    R:  { x: 240.66, y: 162.63, label: "右弧低点" },
    G:  { x: 309,    y: 153,    label: "右边界" },
    B:  { x: 138,    y: 157,    label: "左眼中心" },
    F:  { x: 237,    y: 157,    label: "右眼中心" },
    N:  { x: 187,    y: 170,    label: "鼻中心" },
    J:  { x: 187,    y: 177,    label: "鼻下" },
    ML: { x: 163,    y: 192,    label: "嘴左端" },
    MR: { x: 211,    y: 192,    label: "嘴右端" },
    BL: { x: 92,     y: 185,    label: "左腮红" },
    BR: { x: 281,    y: 185,    label: "右腮红" },
    H:  { x: 187,    y: 48,     label: "头顶" },
    T:  { x: 203,    y: 16,     label: "呆毛" },
    EL: { x: 101,    y: 73,     label: "左耳" },
    ER: { x: 286,    y: 73,     label: "右耳" }
  };

  // ── look-geometry constants (verbatim from idle-look-v2) ──────────────────
  var VIEW_W = 374;
  var TOP_CHAIN = ["A", "L", "C", "D", "E", "R", "G"];
  var BASE = {
    cheekD: "M65 153 C97 159 136 168 172 154 C181 150 193 147 202 154 C238 168 277 159 309 153 C331 178 336 221 303 246 C270 268 104 268 71 246 C38 221 43 178 65 153Z",
    headCapD: "M64 153 C64 88 116 48 187 48 C258 48 310 88 310 153 C310 214 257 253 187 253 C117 253 64 214 64 153Z",
    leftCreaseD: "M62 238 C70 250 84 256 100 256",
    rightCreaseD: "M312 238 C304 250 290 256 274 256"
  };
  var RIGHT_HEAD_CAP_D = "M64 153 C66.12 89.55 117.55 49.81 187 48 C267.24 48 328.48 88 310 153 C310 214 257 253 187 253 C117 253 64 214 64 153Z";
  var LEFT_HEAD_CAP_D = "M64 153 C45.52 88 106.76 48 187 48 C256.45 49.81 307.88 89.55 310 153 C310 214 257 253 187 253 C117 253 64 214 64 153Z";
  var FRONT_TAIL = [
    [331, 178, 336, 221, 303, 246],
    [270, 268, 104, 268, 71, 246],
    [38, 221, 43, 178, 65, 153]
  ];
  var LEFT_TAIL = [
    [320.06, 180.73, 321.87, 218.27, 303, 246],
    [270, 268, 104, 268, 71, 246],
    [35.12, 221, 40.60, 178, 65, 153]
  ];
  var RIGHT_TAIL = [
    [333.40, 178.00, 338.88, 221.00, 303, 246],
    [270, 268, 104, 268, 71, 246],
    [52.13, 218.27, 53.94, 180.73, 65, 153]
  ];
  var PITCH_UP = {
    axis: -25.5, lower: 3.6, faceDy: -21.5, faceSy: 0.93,
    blushDy: -22.41, earDy: 12, tuftDy: 12
  };
  var PITCH_DOWN = {
    axis: 26, lower: -7.9, faceDy: 24.5, faceSy: 1,
    blushDy: 24.5, earDy: -10, tuftDy: -2
  };

  // ── breathing DEFAULTS (verbatim from idle-look-v2 DEFAULTS) ──────────────
  var BREATH = {
    bodyExpand: 3.2,
    bodyTopLift: 1.2,
    bodyBottomDrop: 0.8,
    headFloat: 1.1,
    headNod: -0.25,
    faceLag: 0.25,
    earLag: 0.35,
    tuftFloat: 0.5,
    tieKnotShift: 0.4,
    tieSwing: -1.1
  };
  var BREATH_PERIOD = 4.0; // seconds, sin-driven (matches tuner: breathAmount peaks mid-cycle)

  // ── cursor look mapping (per task spec; v2 defaults for max angles) ───────
  var FACE_CENTER = { x: 187, y: 157 };
  var HALF_W = 150;          // viewBox units; tune for sensitivity
  var HALF_H = 120;
  var mouseYawMax = 55;      // v2 DEFAULTS.mouseYawMax
  var mousePitchMax = 38;    // v2 DEFAULTS.mousePitchMax
  // Host pointer samples are discrete (clawd-on-desk boosts idle polling to
  // about 10Hz while the cursor moves). Render a finite short segment between
  // samples so the whole face moves continuously, then land exactly on the
  // target and freeze. This avoids both moving-time steps and stop-time easing
  // drift.
  var LOOK_INTERP_MS = 150;
  var LOOK_MIN_INTERP_MS = 70;
  var LOOK_TARGET_EPS = 0.0005;
  var SUNGLASSES_EASE = {
    stiffness: 62,
    damping: 11.5,
    dxPerYaw: 0.17,
    dyPerPitch: 0.095,
    rotPerYaw: 0.082,
    rotPerPitch: -0.024,
    maxDx: 4.2,
    maxDy: 2.8,
    maxRot: 2.1
  };

  // ── live look state (replaces the tuner's `state`) ────────────────────────
  // breathProgress is implied by the time-driven sin loop; only yaw/pitch are
  // pointer-driven. We keep a tiny `state`-shaped object so the ported geometry
  // functions read state.yaw / state.pitch unchanged.
  // ── mini patch: mini viewBox(screen) coords -> master coords ──
  // 整体 wrapper = rotate(-90 187 230); 逆变换 = rotate(+90 187 230)。
  // 入口处换算后, 引擎内部 pointerVB / FACE_CENTER / HALF_W/H 全部保持母版系语义。
  var MINI_PIVOT = { x: 187, y: 230 };
  function miniToMasterPoint(p) {
    var dx = p.x - MINI_PIVOT.x;
    var dy = p.y - MINI_PIVOT.y;
    return { x: MINI_PIVOT.x - dy, y: MINI_PIVOT.y + dx };
  }

  var state = { yaw: 0, pitch: 0, breathProgress: 0 };
  var sunglassesPose = { yaw: 0, pitch: 0, yawV: 0, pitchV: 0 };

  var svg = document.getElementById("mini-stage");
  var baseTransform = {};
  var ready = false;

  // ── small math/util helpers (verbatim from idle-look-v2) ──────────────────
  function smooth01(value) {
    var t = clamp(value, 0, 1);
    return t * t * (3 - 2 * t);
  }
  function clamp(value, min, max) {
    return Math.max(min, Math.min(max, value));
  }
  function lerp(a, b, t) {
    return a + (b - a) * t;
  }
  function fmt(value) {
    return String(parseFloat(Number(value).toFixed(3)));
  }
  function numbers(value) {
    return (value.match(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi) || []).map(Number);
  }
  function el(tag, attrs) {
    var node = document.createElementNS(NS, tag);
    attrs = attrs || {};
    for (var key in attrs) {
      if (Object.prototype.hasOwnProperty.call(attrs, key)) {
        var value = attrs[key];
        if (value !== null && value !== undefined) node.setAttribute(key, String(value));
      }
    }
    return node;
  }
  function transformPathPairs(path, fn) {
    var values = numbers(path);
    var output = [];
    for (var i = 0; i < values.length; i += 2) {
      var point = fn({ x: values[i], y: values[i + 1] });
      output.push(point.x, point.y);
    }
    var index = 0;
    return path.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, function () {
      return fmt(output[index++]);
    });
  }

  // ── DOM access helpers (ported, svg-scoped) ───────────────────────────────
  function ensureDefs() {
    var defs = svg.querySelector("defs");
    if (!defs) {
      defs = document.createElementNS(NS, "defs");
      svg.insertBefore(defs, svg.firstElementChild);
    }
    return defs;
  }
  function setAttr(id, name, value) {
    var node = svg.querySelector("#" + id);
    if (!node) return;
    if (value === null || value === undefined || value === "") node.removeAttribute(name);
    else node.setAttribute(name, value);
  }
  function setLayerTransform(id, extraTransform) {
    var node = svg.querySelector("#" + id);
    if (!node) return;
    var transform = [baseTransform[id] || "", extraTransform].filter(Boolean).join(" ");
    if (transform) node.setAttribute("transform", transform);
    else node.removeAttribute("transform");
  }
  function setElementTransform(id, extraTransform) {
    var node = svg.querySelector("#" + id);
    if (!node) return;
    var transform = [baseTransform[id] || "", extraTransform].filter(Boolean).join(" ");
    if (transform) node.setAttribute("transform", transform);
    else node.removeAttribute("transform");
  }

  // ── v2 blush clip contract (verbatim port of prepareBlushClip) ────────────
  // The fix that killed blush jitter in v2: wrapper (carries clip, NO transform
  // of its own) > transformGroup (carries blushPlaneTransform look-slide) >
  // blushes; the wrapper is a child of #head-layer so breathing headMotion is
  // applied exactly once by the parent for both clip and content. Clip path is
  // only ever given d (= same-frame cheek in local coords), never a transform.
  function prepareBlushClip() {
    var blushes = svg.querySelector("#blushes");
    var headLayer = svg.querySelector("#head-layer");
    if (!blushes || !headLayer || svg.querySelector("#idle-look-blush-clip-wrapper")) return;

    var clip = document.createElementNS(NS, "clipPath");
    clip.setAttribute("id", "idle-look-blush-clip");
    clip.setAttribute("clipPathUnits", "userSpaceOnUse");
    var clipPath = document.createElementNS(NS, "path");
    clipPath.setAttribute("id", "idle-look-blush-clip-path");
    clipPath.setAttribute("d", BASE.cheekD);
    clip.appendChild(clipPath);
    ensureDefs().appendChild(clip);

    // wrapper: owns the clip and inherits head-layer breathing only.
    var wrapper = document.createElementNS(NS, "g");
    wrapper.setAttribute("id", "idle-look-blush-clip-wrapper");
    wrapper.setAttribute("data-layer", "idle-blush-clip-host");
    wrapper.setAttribute("clip-path", "url(#idle-look-blush-clip)");

    // transformGroup: moves blush content inside the clip for look-follow.
    var transformGroup = document.createElementNS(NS, "g");
    transformGroup.setAttribute("id", "idle-look-blush-transform");
    transformGroup.appendChild(blushes);
    wrapper.appendChild(transformGroup);

    headLayer.appendChild(wrapper);
  }

  function rememberBaseTransforms() {
    [
      "ears-layer", "head-layer", "head-tufts", "face-layer", "sunglasses",
      "idle-look-blush-clip-wrapper", "idle-look-blush-transform", "tie",
      "tie-shadow", "tie-knot", "tie-blade", "tie-knot-highlight", "tie-center-fold", "tie-left-fold"
    ].forEach(function (id) {
      var node = svg.querySelector("#" + id);
      if (node) baseTransform[id] = node.getAttribute("transform") || "";
    });
  }

  // ── breathing (verbatim ports) ────────────────────────────────────────────
  // breathAmount uses an external phase (0..1 ramp) instead of the tuner slider:
  // sin(PI * phase) so phase 0/1 = rest, 0.5 = inhale peak — identical shape.
  var breathPhase = 0;
  function breathAmount() {
    return Math.sin(Math.PI * clamp(breathPhase, 0, 1));
  }
  function bodyBreathPath(b) {
    var expand = BREATH.bodyExpand * b;
    var topLift = BREATH.bodyTopLift * b;
    var bottomDrop = BREATH.bodyBottomDrop * b;
    var leftX = 60 - expand;
    var rightX = 314 + expand;
    var topY = 200 - topLift;
    var bottomY = 412 + bottomDrop * .35;
    var lowerCtrlY = 380 + bottomDrop;
    return [
      "M187 " + fmt(topY),
      "C " + fmt(113 - expand * .58) + " " + fmt(topY) + " " + fmt(leftX) + " 251 " + fmt(leftX) + " 322",
      "C " + fmt(leftX) + " " + fmt(lowerCtrlY) + " 101 " + fmt(bottomY) + " 187 " + fmt(bottomY),
      "C 273 " + fmt(bottomY) + " " + fmt(rightX) + " " + fmt(lowerCtrlY) + " " + fmt(rightX) + " 322",
      "C " + fmt(rightX) + " 251 " + fmt(261 + expand * .58) + " " + fmt(topY) + " 187 " + fmt(topY) + "Z"
    ].join(" ");
  }
  function translateY(y) {
    return Math.abs(y) < 1e-6 ? "" : "translate(0 " + fmt(y) + ")";
  }
  function translate(x, y) {
    return Math.abs(x) < 1e-6 && Math.abs(y) < 1e-6 ? "" : "translate(" + fmt(x) + " " + fmt(y) + ")";
  }
  function rotateAroundHead(angle) {
    return Math.abs(angle) < 1e-6 ? "" : "rotate(" + fmt(angle) + " 187 205)";
  }
  function rotateAroundTuft(angle) {
    return Math.abs(angle) < 1e-6 ? "" : "rotate(" + fmt(angle) + " 198 48)";
  }
  function composeBreathTransforms() {
    var parts = Array.prototype.slice.call(arguments);
    return parts.filter(Boolean).join(" ");
  }
  function applyTieBreathMotion(b) {
    var knotDx = BREATH.tieKnotShift * b;
    var swing = BREATH.tieSwing * b;
    var knotMove = Math.abs(knotDx) < 1e-6 ? "" : "translate(" + fmt(knotDx) + " 0)";
    var bladeSwing = Math.abs(knotDx) < 1e-6 && Math.abs(swing) < 1e-6
      ? ""
      : (knotMove + " rotate(" + fmt(swing) + " 34 14)").trim();
    ["tie-knot", "tie-knot-highlight"].forEach(function (id) { setElementTransform(id, knotMove); });
    ["tie-shadow", "tie-blade", "tie-center-fold", "tie-left-fold"].forEach(function (id) { setElementTransform(id, bladeSwing); });
  }

  // ── look geometry (verbatim ports) ────────────────────────────────────────
  function headLookActive() {
    return Math.abs(state.yaw) > .001 || Math.abs(state.pitch) > .001;
  }
  function axisT(value) {
    return smooth01(Math.abs(value) / 100);
  }
  function diagonalFactor() {
    return Math.abs(state.yaw) / 100 * Math.abs(state.pitch) / 100;
  }
  function trimmed(value, trimScale) {
    if (trimScale === undefined) trimScale = 1;
    var trim = 1 - diagonalFactor() * 15 / 100 * trimScale;
    return value * trim;
  }
  function smoothRange(start, end, value) {
    return smooth01(clamp((value - start) / (end - start), 0, 1));
  }
  function mixPoint(a, b, t) {
    return { x: lerp(a.x, b.x, t), y: lerp(a.y, b.y, t) };
  }
  function interpolateNumberString(from, to, t) {
    var a = numbers(from);
    var b = numbers(to);
    var index = 0;
    if (!from || !to || a.length !== b.length) return t < 1 ? from : to;
    return from.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, function () {
      var val = lerp(a[index], b[index] !== undefined ? b[index] : a[index - 1], t);
      index += 1;
      return fmt(val);
    });
  }
  function transformTopPoint(point, dir) {
    var axisX = dir < 0 ? 125 : 249;
    var axisTravel = (axisX - VIEW_W / 2) * .75;
    var localX = point.x - axisX;
    var next = { x: axisTravel + axisX + localX, y: point.y };
    var a = rawAnchors.A || { x: 65 };
    var g = rawAnchors.G || { x: 309 };
    var weightT = clamp((point.x - a.x) / (g.x - a.x), 0, 1);
    var weight = Math.pow(Math.sin(Math.PI * weightT), .9);
    return {
      x: point.x + (next.x - point.x) * weight,
      y: point.y
    };
  }
  function catmullPath(points, tension, sharpness) {
    if (tension === undefined) tension = .72;
    if (sharpness === undefined) sharpness = .34;
    var segs = ["M" + fmt(points[0].x) + " " + fmt(points[0].y)];
    for (var i = 0; i < points.length - 1; i += 1) {
      var p0 = points[Math.max(0, i - 1)];
      var p1 = points[i];
      var p2 = points[i + 1];
      var p3 = points[Math.min(points.length - 1, i + 2)];
      var nearBridge = ["C", "D", "E"].indexOf(p1.id) !== -1 || ["C", "D", "E"].indexOf(p2.id) !== -1;
      var localTension = tension * (nearBridge ? (1 - sharpness * .42) : 1);
      var c1 = {
        x: p1.x + (p2.x - p0.x) * localTension / 6,
        y: p1.y + (p2.y - p0.y) * localTension / 6
      };
      var c2 = {
        x: p2.x - (p3.x - p1.x) * localTension / 6,
        y: p2.y - (p3.y - p1.y) * localTension / 6
      };
      segs.push("C" + fmt(c1.x) + " " + fmt(c1.y) + " " + fmt(c2.x) + " " + fmt(c2.y) + " " + fmt(p2.x) + " " + fmt(p2.y));
    }
    return segs.join(" ");
  }
  function continuousYawFaceBasePath() {
    var top = TOP_CHAIN.map(function (id) {
      var point = rawAnchors[id];
      return { id: id, x: point.x, y: point.y };
    });
    var tail = FRONT_TAIL.map(function (seg) {
      return "C" + fmt(seg[0]) + " " + fmt(seg[1]) + " " + fmt(seg[2]) + " " + fmt(seg[3]) + " " + fmt(seg[4]) + " " + fmt(seg[5]);
    }).join(" ");
    return catmullPath(top) + " " + tail + "Z";
  }
  function yawFacePath() {
    var dir = Math.sign(state.yaw);
    var t = axisT(state.yaw);
    if (TOP_CHAIN.some(function (id) { return !rawAnchors[id]; })) return BASE.cheekD;
    if (!dir || t <= .001) return continuousYawFaceBasePath();
    var top = TOP_CHAIN.map(function (id) {
      var start = rawAnchors[id];
      var end = transformTopPoint(start, dir);
      var m = mixPoint(start, end, t);
      return { id: id, x: m.x, y: m.y };
    });
    var sideTail = dir < 0 ? LEFT_TAIL : RIGHT_TAIL;
    var tail = FRONT_TAIL.map(function (seg, index) {
      var mixed = seg.map(function (value, numberIndex) { return lerp(value, sideTail[index][numberIndex], t); });
      return "C" + fmt(mixed[0]) + " " + fmt(mixed[1]) + " " + fmt(mixed[2]) + " " + fmt(mixed[3]) + " " + fmt(mixed[4]) + " " + fmt(mixed[5]);
    }).join(" ");
    return catmullPath(top) + " " + tail + "Z";
  }
  function faceLowerEffect() {
    if (state.pitch <= 0) return 0;
    return axisT(state.pitch) * lerp(.45, 1, axisT(state.yaw));
  }
  function faceLowerWrappedPoint(point) {
    var effect = faceLowerEffect();
    if (effect <= .001) return point;
    var lower = smoothRange(238, 263, point.y);
    if (lower <= .001) return point;
    var side = Math.sign(point.x - 187);
    return {
      x: point.x + side * 6 * effect * lower * .3,
      y: point.y + 12 * effect * lower
    };
  }
  function faceLowerWrappedPath(path) {
    return transformPathPairs(path, faceLowerWrappedPoint);
  }
  function pitchDeltaY(y) {
    if (state.pitch === 0) return 0;
    var sign = Math.sign(state.pitch);
    var t = axisT(state.pitch);
    var lowerWeight = clamp((y - 166) / 92, 0, 1);
    if (sign < 0) return lerp(PITCH_UP.axis, PITCH_UP.lower, lowerWeight) * t;
    return lerp(PITCH_DOWN.axis, PITCH_DOWN.lower, lowerWeight) * t;
  }
  function warpPathForPitch(path) {
    var index = 0;
    return path.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, function (value) {
      var n = Number(value);
      var next = index % 2 === 1 ? n + pitchDeltaY(n) : n;
      index += 1;
      return fmt(next);
    });
  }
  function cheekPath() {
    return faceLowerWrappedPath(warpPathForPitch(yawFacePath()));
  }
  function headCapPath() {
    var yawT = axisT(state.yaw);
    var dir = Math.sign(state.yaw);
    var yawTarget = dir > 0 ? RIGHT_HEAD_CAP_D : LEFT_HEAD_CAP_D;
    var yawPath = dir ? interpolateNumberString(BASE.headCapD, yawTarget, yawT) : BASE.headCapD;
    var index = 0;
    return yawPath.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, function (value) {
      var n = Number(value);
      if (index % 2 === 0) {
        index += 1;
        return fmt(n);
      }
      var topWeight = clamp((120 - n) / 80, 0, 1);
      var sideWeight = clamp((n - 120) / 70, 0, 1);
      var sign = Math.sign(state.pitch);
      var t = axisT(state.pitch);
      var delta = sign < 0
        ? (2 * topWeight - 5.61 * sideWeight) * t
        : (-1.87 * topWeight + 7.28 * sideWeight) * t;
      index += 1;
      return fmt(n + delta);
    });
  }
  function creasePath(side) {
    var isLeft = side === "left";
    var base = BASE[isLeft ? "leftCreaseD" : "rightCreaseD"];
    var sideSign = isLeft ? 1 : -1;
    var startX = isLeft ? 62 : 312;
    var baseLength = 38;
    var yawT = axisT(state.yaw);
    var yawPull = Math.sign(state.yaw) * yawT;
    var pitchT = axisT(state.pitch);
    return transformPathPairs(base, function (point) {
      var along = isLeft
        ? clamp((point.x - 62) / baseLength, 0, 1)
        : clamp((312 - point.x) / baseLength, 0, 1);
      var next = {
        x: startX + (point.x - startX),
        y: point.y
      };
      next.x += yawPull * (isLeft ? 1 : -1) * lerp(3, 6, along);
      next.x += sideSign * lerp(1.8, 2.4, along) * pitchT;
      next.y += pitchDeltaY(point.y);
      return faceLowerWrappedPoint(next);
    });
  }
  function facePlaneTransform(withPitchScale) {
    var dir = Math.sign(state.yaw);
    var yawT = axisT(state.yaw);
    var axis = 187 + dir * 62 * yawT;
    var dx = dir * 46.5 * yawT;
    var pitchSign = Math.sign(state.pitch);
    var pitchT = axisT(state.pitch);
    var pitchData = pitchSign < 0 ? PITCH_UP : PITCH_DOWN;
    var dy = trimmed(pitchData.faceDy * pitchT, .45);
    var sy = withPitchScale ? lerp(1, pitchData.faceSy, pitchT) : 1;
    return "translate(" + fmt(dx) + " " + fmt(dy) + ") translate(" + fmt(axis) + " 172) skewX(0) scale(1 " + fmt(sy) + ") translate(" + fmt(-axis) + " -172)";
  }
  function blushPlaneTransform() {
    var dir = Math.sign(state.yaw);
    var yawT = axisT(state.yaw);
    var axis = 187 + dir * 62 * yawT;
    var dx = dir * 46.5 * yawT;
    var pitchSign = Math.sign(state.pitch);
    var pitchT = axisT(state.pitch);
    var pitchData = pitchSign < 0 ? PITCH_UP : PITCH_DOWN;
    var dy = trimmed(pitchData.blushDy * pitchT, .35);
    return "translate(" + fmt(dx) + " " + fmt(dy) + ") translate(" + fmt(axis) + " 172) skewX(0) scale(1 1) translate(" + fmt(-axis) + " -172)";
  }
  function centeredTransform(origin, dx, dy, sx, sy) {
    if (sx === undefined) sx = 1;
    if (sy === undefined) sy = 1;
    if (Math.abs(dx) < 1e-6 && Math.abs(dy) < 1e-6 && Math.abs(sx - 1) < 1e-6 && Math.abs(sy - 1) < 1e-6) return "";
    return "translate(" + fmt(origin.x + dx) + " " + fmt(origin.y + dy) + ") scale(" + fmt(sx) + " " + fmt(sy) + ") translate(" + fmt(-origin.x) + " " + fmt(-origin.y) + ")";
  }
  function springValue(value, target, velocity, dt) {
    var accel = (target - value) * SUNGLASSES_EASE.stiffness - velocity * SUNGLASSES_EASE.damping;
    velocity += accel * dt;
    value += velocity * dt;
    if (Math.abs(target - value) < 0.0008 && Math.abs(velocity) < 0.0008) {
      value = target;
      velocity = 0;
    }
    return { value: value, velocity: velocity };
  }
  function updateSunglassesEase(dt) {
    var yaw = springValue(sunglassesPose.yaw, state.yaw, sunglassesPose.yawV, dt);
    var pitch = springValue(sunglassesPose.pitch, state.pitch, sunglassesPose.pitchV, dt);
    sunglassesPose.yaw = yaw.value;
    sunglassesPose.yawV = yaw.velocity;
    sunglassesPose.pitch = pitch.value;
    sunglassesPose.pitchV = pitch.velocity;
  }
  function sunglassesEaseTransform() {
    var lagYaw = sunglassesPose.yaw - state.yaw;
    var lagPitch = sunglassesPose.pitch - state.pitch;
    var dx = clamp(lagYaw * SUNGLASSES_EASE.dxPerYaw, -SUNGLASSES_EASE.maxDx, SUNGLASSES_EASE.maxDx);
    var dy = clamp(lagPitch * SUNGLASSES_EASE.dyPerPitch, -SUNGLASSES_EASE.maxDy, SUNGLASSES_EASE.maxDy);
    var rot = clamp(
      lagYaw * SUNGLASSES_EASE.rotPerYaw + lagPitch * SUNGLASSES_EASE.rotPerPitch,
      -SUNGLASSES_EASE.maxRot,
      SUNGLASSES_EASE.maxRot
    );
    var pulse = clamp((Math.abs(lagYaw) + Math.abs(lagPitch)) * 0.00055, 0, 0.012);
    if (Math.abs(dx) < 0.002 && Math.abs(dy) < 0.002 && Math.abs(rot) < 0.002 && pulse < 0.0005) return "";
    return "translate(" + fmt(187 + dx) + " " + fmt(157 + dy) + ") rotate(" + fmt(rot) + ") scale(" + fmt(1 + pulse) + " " + fmt(1 - pulse * 0.35) + ") translate(-187 -157)";
  }
  function elementOffsets() {
    var dir = Math.sign(state.yaw);
    var yawT = axisT(state.yaw);
    var pitchSign = Math.sign(state.pitch);
    var pitchT = axisT(state.pitch);
    var pitchUp = pitchSign < 0;
    var pitchEye = pitchUp ? -.56 * pitchT : 0;
    var pitchBlushDx = pitchUp ? 3.5 * pitchT : -1.8 * pitchT;
    var yawLeftEye = dir < 0 ? -2 * yawT : 0;
    var yawRightEye = dir > 0 ? 2 * yawT : 0;
    var leftBlushYaw = dir < 0
      ? { dx: 6.5 * yawT, dy: 0, sx: 1, sy: 1 }
      : { dx: -24 * yawT, dy: 20.5 * yawT, sx: lerp(1, 1.09, yawT), sy: lerp(1, 1.1, yawT) };
    var rightBlushYaw = dir < 0
      ? { dx: 25 * yawT, dy: 20.5 * yawT, sx: lerp(1, 1.09, yawT), sy: lerp(1, 1.1, yawT) }
      : { dx: -5.5 * yawT, dy: 0, sx: 1, sy: 1 };
    return {
      leftEye: { dx: yawLeftEye, dy: pitchEye },
      rightEye: { dx: yawRightEye, dy: pitchEye },
      leftBlush: {
        dx: leftBlushYaw.dx + pitchBlushDx,
        dy: leftBlushYaw.dy,
        sx: leftBlushYaw.sx,
        sy: leftBlushYaw.sy
      },
      rightBlush: {
        dx: rightBlushYaw.dx - pitchBlushDx,
        dy: rightBlushYaw.dy,
        sx: rightBlushYaw.sx,
        sy: rightBlushYaw.sy
      }
    };
  }
  function earState() {
    var dir = Math.sign(state.yaw);
    var yawT = axisT(state.yaw);
    var pitchSign = Math.sign(state.pitch);
    var pitchT = axisT(state.pitch);
    var pitchData = pitchSign < 0 ? PITCH_UP : PITCH_DOWN;
    var pitchDy = pitchData.earDy * pitchT;
    var left = { x: 0, y: pitchDy, grow: 0 };
    var right = { x: 0, y: pitchDy, grow: 0 };
    if (dir < 0) {
      left.x += -3.5 * yawT;
      left.y += 3.5 * yawT;
      right.grow = smoothRange(.12, 1, yawT);
    } else if (dir > 0) {
      right.x += -9.5 * yawT;
      right.y += 3.5 * yawT;
      left.grow = smoothRange(.12, 1, yawT);
    }
    return { left: left, right: right };
  }
  function tuftLookTransform() {
    var dir = Math.sign(state.yaw);
    var yawT = axisT(state.yaw);
    var pitchSign = Math.sign(state.pitch);
    var pitchT = axisT(state.pitch);
    var pitchData = pitchSign < 0 ? PITCH_UP : PITCH_DOWN;
    var yawDx = dir < 0 ? -21.7 * yawT : dir > 0 ? -10.3 * yawT : 0;
    var pitchDy = pitchData.tuftDy * pitchT;
    return translate(yawDx, pitchDy);
  }

  // ── combined per-frame application (port of applyBreathPose + applyHeadBreathMotion,
  //    hand-redraw section removed per task spec) ────────────────────────────
  function applyHeadBreathMotion(b) {
    var headY = -BREATH.headFloat * b;
    var nod = BREATH.headNod * b;
    var faceLagY = BREATH.faceLag * b;
    var earLagY = BREATH.earLag * b;
    var tuftY = headY - BREATH.tuftFloat * b;
    var headMotion = composeBreathTransforms(
      translateY(headY),
      rotateAroundHead(nod)
    );
    var faceMotion = composeBreathTransforms(
      translateY(headY + faceLagY),
      rotateAroundHead(nod * .82)
    );
    var earMotion = composeBreathTransforms(
      translateY(headY + earLagY),
      rotateAroundHead(nod * .35)
    );
    var tuftBreathMotion = composeBreathTransforms(
      translateY(tuftY),
      rotateAroundTuft(nod * -.9)
    );
    var lookActive = headLookActive();
    var cheek = cheekPath();
    var elem = elementOffsets();
    var ears = earState();

    setAttr("head-cap-fill", "d", headCapPath());
    setAttr("cheek-muzzle-fill", "d", cheek);
    // v2: clip path tracks the same-frame cheek in local coords, but never takes
