    // wrapper inherits breathing from head-layer; keep it transform-free.
    setLayerTransform("idle-look-blush-clip-wrapper", "");
    setElementTransform("idle-look-blush-transform", lookActive ? blushPlaneTransform() : "");
    setLayerTransform("ears-layer", earMotion);
    setLayerTransform("head-tufts", composeBreathTransforms(lookActive ? tuftLookTransform() : "", tuftBreathMotion));

    setAttr("left-ear", "transform", lookActive ? translate(ears.left.x, ears.left.y) : "");
    setAttr("right-ear", "transform", lookActive ? translate(ears.right.x, ears.right.y) : "");
    setAttr("left-ear-outer", "r", fmt(lerp(34, 37.4, ears.left.grow)));
    setAttr("left-ear-inner", "r", fmt(lerp(18, 19.8, ears.left.grow)));
    setAttr("right-ear-outer", "r", fmt(lerp(34, 37.4, ears.right.grow)));
    setAttr("right-ear-inner", "r", fmt(lerp(18, 19.8, ears.right.grow)));

    setAttr("left-eye", "rx", "12.5");
    setAttr("right-eye", "rx", "12.5");
    setAttr("left-eye", "ry", "17");
    setAttr("right-eye", "ry", "17");
    setAttr("left-eye", "transform", centeredTransform({ x: 138, y: 157 }, elem.leftEye.dx, elem.leftEye.dy));
    setAttr("right-eye", "transform", centeredTransform({ x: 237, y: 157 }, elem.rightEye.dx, elem.rightEye.dy));
    setAttr("left-blush", "transform", centeredTransform({ x: 92, y: 185 }, elem.leftBlush.dx, elem.leftBlush.dy, elem.leftBlush.sx, elem.leftBlush.sy));
    setAttr("right-blush", "transform", centeredTransform({ x: 281, y: 185 }, elem.rightBlush.dx, elem.rightBlush.dy, elem.rightBlush.sx, elem.rightBlush.sy));
