  }
  function applyBreathPose() {
    var b = breathAmount();
    var body = svg.querySelector("#body-belly-fill");
    if (body) body.setAttribute("d", Math.abs(b) < 1e-6 ? bodyBreathPath(0) : bodyBreathPath(b));
    applyHeadBreathMotion(b);
    setLayerTransform("tie", "");
    applyTieBreathMotion(b);
  }
  // render(): the tuner's render() minus all diagnostics + hand re-draw.
  function render() {
    if (!svg || !ready) return;
    applyBreathPose();
  }

  // ── pointer → yaw/pitch target (per task spec; viewBox coords) ────────────
  var pointerInside = false;
  var pointerVB = { x: FACE_CENTER.x, y: FACE_CENTER.y };
  var targetYaw = 0;
  var targetPitch = 0;
  var lookFromYaw = 0;
  var lookFromPitch = 0;
  var lookToYaw = 0;
  var lookToPitch = 0;
  var lookStartMs = 0;
  var lookDurationMs = 0;

  function nowMs() {
    return window.performance && typeof window.performance.now === "function"
      ? window.performance.now()
      : Date.now();
  }

  function currentLookAt(now) {
    if (!lookDurationMs) return { yaw: lookToYaw, pitch: lookToPitch };
    var t = clamp((now - lookStartMs) / lookDurationMs, 0, 1);
    var eased = smooth01(t);
