    targetYaw = yaw;
    targetPitch = pitch;
    if (Math.abs(yaw - lookToYaw) < LOOK_TARGET_EPS && Math.abs(pitch - lookToPitch) < LOOK_TARGET_EPS) return;

    var now = nowMs();
    var current = currentLookAt(now);
    var distance = Math.sqrt(Math.pow(yaw - current.yaw, 2) + Math.pow(pitch - current.pitch, 2));
    lookFromYaw = current.yaw;
    lookFromPitch = current.pitch;
    lookToYaw = yaw;
    lookToPitch = pitch;
    lookStartMs = now;
    lookDurationMs = distance < 1 ? LOOK_MIN_INTERP_MS : LOOK_INTERP_MS;
  }

  function updateLookTarget() {
    if (!pointerInside) {
      setLookTarget(0, 0);
      return;
    }
    var xRatio = clamp((pointerVB.x - FACE_CENTER.x) / HALF_W, -1, 1);
    var yRatio = clamp((pointerVB.y - FACE_CENTER.y) / HALF_H, -1, 1);
