    if (!r.width || !r.height) return;
    var vb = svg.viewBox && svg.viewBox.baseVal ? svg.viewBox.baseVal : { x: -53, y: -10, width: 480, height: 480 };
    var fp = miniToMasterPoint({
      x: vb.x + (e.clientX - r.left) * (vb.width / r.width),
      y: vb.y + (e.clientY - r.top) * (vb.height / r.height)
