  svg.addEventListener("mouseleave", function () { pointerInside = false; updateLookTarget(); });

  // ── rAF loop (low-power pause aware, mirrors cloudling) ───────────────────
  var lowPowerPaused = false;
  var rafId = 0;
  var lastT = 0;
  var startT = 0;
  var lowPowerPausedAt = 0;
  var lowPowerPausedTotal = 0;

