    rafId = 0;
    if (lowPowerPaused) return;
    var dt = (now - lastT) / 1000;
    if (!(dt >= 0)) dt = 0;
    if (dt > 0.1) dt = 0.1; // clamp big gaps (tab refocus) so easing stays sane
    lastT = now;
    var t = (now - startT - lowPowerPausedTotal) / 1000;

    // breathing phase: 0..1 ramp from a sin time base; sin(PI*phase) inside
    // breathAmount yields rest→inhale→rest over BREATH_PERIOD seconds.
    breathPhase = (Math.cos(2 * Math.PI * t / BREATH_PERIOD) + 1) / 2; // 0..1, 0 at t=0

