(() => {
  "use strict";
  const SVG_NS = "http://www.w3.org/2000/svg";
  const svg = document.getElementById("mini-stage");

  // ── 可调参数（tuner state；定稿后烘焙抄 JSON）──
  const state = {
    speed: 1,
    boardX: -58, boardY: 92, boardScale: 1.15, boardRot: -6, boardFloat: 2.6, boardSwing: 1.45, boardIntroShake: 5.6, boardPostSway: 12.5, boardBreathScale: 0.025,
    tickGap: 0.30, tickDur: 0.18, tickKick: 0.65, tickRotKick: 0.95, checkPalette: 0,
    donePalette: 0, doneStroke: 7,
    lookYaw: 0.85, lookPitch: 0.6, stareDur: 0.6,
    bloomDur: 0.22, bloomHold: 0.7, mouthOpenMax: 100, browLift: 3, tuftPerk: -20,
    mouthPulse: 0.5, tuftFloat: 2, tieSway: 0.4
  };
  let autoLoop = /[?&]loop=1/.test((typeof location !== "undefined" && location.search) || ""); // 默认播一次; ?loop=1 循环重播(showcase 先例)

  // 勾色票（鹿鹿参考图正红 / 人物深棕 / 低饱和柔绿）
  const CHECK_PALETTES = [
    { name: "正红", color: "#e25555" },
    { name: "深棕", color: "#7b4a23" },
    { name: "柔绿", color: "#7fb069" }
  ];
  // 结算大勾色票（鹿鹿口径：绿色；三档绿给鹿鹿点）
  const DONE_PALETTES = [
    { name: "柔绿", color: "#7fb069" },
    { name: "草绿", color: "#5cb85c" },
    { name: "翠绿", color: "#3da568" }
  ];

  // ── 分镜时间线（依滑块动态算）──
  function timeline() {
    const t1 = 0.45;                                  // 卡片首帧已在场；留 0.45s 给空清单先被看见
    const tick1 = t1 + 0.12;                          // 勾1 开始描画
    const tick2 = tick1 + state.tickGap;
    const tick3 = tick1 + state.tickGap * 2;
    const tLook = tick1 + 0.10;                       // 勾1 画一半被吸引 → 阶跃回头（引擎 150ms 快转）
    const tSee = tick3 + state.tickDur;               // 三勾全落定
    const tMorph = tSee + 0.10;                       // 清单结算变身：条目+三勾淡出，大绿勾描画（鹿鹿口径）
    const tBloom = tSee + state.stareDur;             // 凝视（含看到变身）→ 绽放笑脸（看着卡片笑）
    const tBack = tBloom + state.bloomHold;           // 带笑回正
    const holdStart = tBack + 0.45;                   // 回正到位 → 保持循环
    return { t1, tick1, tick2, tick3, tLook, tSee, tMorph, tBloom, tBack, holdStart };
  }

  // ── 工具（confirmed 风格；fmt 防 200→20 坑）──
  function clamp(v, a, b) { return Math.max(a, Math.min(b, v)); }
  function lerp(a, b, t) { return a + (b - a) * t; }
  function smooth01(v) { const t = clamp(v, 0, 1); return t * t * (3 - 2 * t); }
  function smoothRange(a, b, v) { return smooth01(clamp((v - a) / (b - a), 0, 1)); }
  function easeOutBack(v) { const t = clamp(v, 0, 1) - 1; return 1 + t * t * (2.70158 * t + 1.70158); }
  function easeOutCubic(x) { return 1 - Math.pow(1 - clamp(x, 0, 1), 3); }
  function fmt(v) { return String(parseFloat(Number(v).toFixed(2))); }
  function el(tag, attrs) {
    const node = document.createElementNS(SVG_NS, tag);
    for (const k in attrs) if (attrs[k] !== null && attrs[k] !== undefined) node.setAttribute(k, String(attrs[k]));
    return node;
  }
  function setT(id, transform) {
    const node = svg.querySelector(`#${id}`);
    if (!node) return;
    if (transform) node.setAttribute("transform", transform);
    else node.removeAttribute("transform");
  }

  // ── 开心嘴 rig（主线 attention 定稿 task-complete-loop-v1 逐字搬运：opening clip > door clip > 三层 fill；W 线最上）──
  const MOUTH = {
    cx: 187, cavityY: 205, lowerCavityY: 218,
    sideY: 200, bottomY: 219.5, halfW: 6, doorInset: 8.5, doorRound: 13,
    cavityW: 25, cavityH: 45, lowerCavityW: 13, lowerCavityH: 8,
    // 保持段脉动（主线 LOOP_MOTION 同名参数）
    bottomPulse: 1.25, insetPulse: 1.1, halfPulse: 0.45, roundPulse: 0.75
  };
  let mouthProgress = 0;   // 0..100（mouthOpenMax 封顶）
  let mouthPulseT = 0;     // 0..1 保持段脉动
  function installMouthRig() {
    const noseMouth = svg.querySelector("#nose-mouth");
    const nose = svg.querySelector("#nose-fill");
    const left = svg.querySelector("#mouth-left");
    const right = svg.querySelector("#mouth-right");
    if (!noseMouth || svg.querySelector("#mouth-interior-clipped")) return;
    let defs = svg.querySelector("defs");
    const openingClip = el("clipPath", { id: "happy-mouth-opening-clip", clipPathUnits: "userSpaceOnUse" });
    openingClip.appendChild(el("path", { id: "mouth-opening-clip-path" }));
    const doorClip = el("clipPath", { id: "happy-mouth-door-clip", clipPathUnits: "userSpaceOnUse" });
    doorClip.appendChild(el("path", { id: "mouth-door-clip-path" }));
    defs.appendChild(openingClip);
    defs.appendChild(doorClip);
    const interior = el("g", { id: "mouth-interior-clipped", "clip-path": "url(#happy-mouth-opening-clip)" });
    const door = el("g", { id: "mouth-door-clipped", "clip-path": "url(#happy-mouth-door-clip)" });
    door.appendChild(el("path", { id: "mouth-inner-shade", fill: "#5b221f", opacity: ".36" }));
    door.appendChild(el("path", { id: "mouth-cavity-fill", fill: "#8c2f2a" }));
    door.appendChild(el("path", { id: "mouth-lower-cavity-fill", fill: "#f58d86" }));
    interior.appendChild(door);
    const strokes = el("g", { id: "mouth-visible-strokes" });
    strokes.appendChild(left);
    strokes.appendChild(right);
    noseMouth.insertBefore(interior, nose.nextSibling);
    noseMouth.appendChild(strokes);
  }
  function mouthClipParams() {
    const pulse = clamp(mouthPulseT, 0, 1) * state.mouthPulse;
    return {
      sideY: MOUTH.sideY,
      bottomY: MOUTH.bottomY + MOUTH.bottomPulse * pulse,
      halfW: MOUTH.halfW + MOUTH.halfPulse * pulse,
      doorInset: MOUTH.doorInset - MOUTH.insetPulse * pulse,
      doorRound: MOUTH.doorRound + MOUTH.roundPulse * pulse
    };
  }
  function mouthOpeningClipD() {
    const p = clamp(mouthProgress / 100, 0, 1);
    const cx = MOUTH.cx;
    const mouth = mouthClipParams();
    const sideY = mouth.sideY;
    if (p <= 0.01) {
      return [
        `M ${fmt(cx - 0.35)} ${fmt(sideY)}`,
        `C ${fmt(cx - 0.35)} ${fmt(sideY)} ${fmt(cx - 0.15)} ${fmt(sideY)} ${fmt(cx)} ${fmt(sideY)}`,
        `C ${fmt(cx + 0.15)} ${fmt(sideY)} ${fmt(cx + 0.35)} ${fmt(sideY)} ${fmt(cx + 0.35)} ${fmt(sideY)}`,
        `C ${fmt(cx + 0.35)} ${fmt(sideY + 0.15)} ${fmt(cx + 0.18)} ${fmt(sideY + 0.2)} ${fmt(cx)} ${fmt(sideY + 0.2)}`,
        `C ${fmt(cx - 0.18)} ${fmt(sideY + 0.2)} ${fmt(cx - 0.35)} ${fmt(sideY + 0.15)} ${fmt(cx - 0.35)} ${fmt(sideY)} Z`
      ].join(" ");
    }
