    const topYShift = (sideY - 199) * 0.18;
    const tx = (x) => x + dx;
    const ty = (y) => y + topYShift;
    const fullBottomDrop = Math.max(0.15, mouth.bottomY - sideY);
    const bottomDrop = fullBottomDrop * p;
    const bottomY = sideY + bottomDrop;
    const bottomW = Math.max(6, mouth.halfW);
    return [
      `M ${fmt(tx(163))} ${fmt(ty(192))}`,
      `C ${fmt(tx(163))} ${fmt(ty(195))} ${fmt(tx(166))} ${fmt(ty(198))} ${fmt(tx(171))} ${fmt(ty(198))}`,
      `C ${fmt(tx(180))} ${fmt(ty(198))} ${fmt(tx(187))} ${fmt(ty(190))} ${fmt(tx(187))} ${fmt(ty(177))}`,
      `C ${fmt(tx(187))} ${fmt(ty(190))} ${fmt(tx(194))} ${fmt(ty(198))} ${fmt(tx(203))} ${fmt(ty(198))}`,
      `C ${fmt(tx(208))} ${fmt(ty(198))} ${fmt(tx(211))} ${fmt(ty(195))} ${fmt(tx(211))} ${fmt(ty(192))}`,
      `C ${fmt(tx(211))} ${fmt(bottomY - bottomDrop * 0.15)} ${fmt(cx + bottomW)} ${fmt(bottomY)} ${fmt(cx)} ${fmt(bottomY)}`,
      `C ${fmt(cx - bottomW)} ${fmt(bottomY)} ${fmt(tx(163))} ${fmt(bottomY - bottomDrop * 0.15)} ${fmt(tx(163))} ${fmt(ty(192))} Z`
    ].join(" ");
  }
  function mouthDoorClipD() {
    const mouth = mouthClipParams();
    const inset = clamp(mouth.doorInset, 0, 22);
    const cx = MOUTH.cx;
    const topY = 166;
    const tailY = 292;
    const sideY = mouth.sideY;
    const bottomY = mouth.bottomY;
    const left = 163 + inset;
    const right = 211 - inset;
    const lowerLeft = Math.max(left, cx - Math.max(0.1, mouth.halfW));
    const lowerRight = Math.min(right, cx + Math.max(0.1, mouth.halfW));
    const round = clamp(mouth.doorRound || 0, 0, Math.max(0.1, bottomY - sideY));
    const curveStartY = clamp(bottomY - round, sideY, bottomY - 0.1);
    const sideHandleY = lerp(curveStartY, bottomY, 0.72);
    const bottomHandleY = bottomY - round * 0.15;
    if (round <= 0.01) {
      return [
        `M ${fmt(left)} ${fmt(topY)}`, `L ${fmt(right)} ${fmt(topY)}`,
        `L ${fmt(right)} ${fmt(tailY)}`, `L ${fmt(left)} ${fmt(tailY)} Z`
      ].join(" ");
    }
    return [
      `M ${fmt(left)} ${fmt(topY)}`,
      `L ${fmt(right)} ${fmt(topY)}`,
      `L ${fmt(right)} ${fmt(curveStartY)}`,
      `C ${fmt(right)} ${fmt(sideHandleY)} ${fmt(lowerRight)} ${fmt(bottomHandleY)} ${fmt(lowerRight)} ${fmt(bottomY)}`,
      `L ${fmt(lowerRight)} ${fmt(tailY)}`,
      `L ${fmt(lowerLeft)} ${fmt(tailY)}`,
      `L ${fmt(lowerLeft)} ${fmt(bottomY)}`,
      `C ${fmt(lowerLeft)} ${fmt(bottomHandleY)} ${fmt(left)} ${fmt(sideHandleY)} ${fmt(left)} ${fmt(curveStartY)}`,
      `L ${fmt(left)} ${fmt(topY)} Z`
    ].join(" ");
  }
  function mouthCavityD() {
    const cx = MOUTH.cx;
    const cy = MOUTH.cavityY;
    const w = MOUTH.cavityW;
    const h = MOUTH.cavityH;
    return [
      `M ${fmt(cx - w)} ${fmt(cy)}`,
      `C ${fmt(cx - w)} ${fmt(cy - h * 0.55)} ${fmt(cx + w)} ${fmt(cy - h * 0.55)} ${fmt(cx + w)} ${fmt(cy)}`,
      `C ${fmt(cx + w)} ${fmt(cy + h * 0.66)} ${fmt(cx - w)} ${fmt(cy + h * 0.66)} ${fmt(cx - w)} ${fmt(cy)} Z`
    ].join(" ");
  }
  function mouthLowerCavityD() {
    const p = clamp((mouthProgress - 18) / 82, 0, 1);
    const cx = MOUTH.cx;
    const cy = MOUTH.lowerCavityY;
    const w = Math.max(0.1, MOUTH.lowerCavityW * p);
    const h = Math.max(0.1, MOUTH.lowerCavityH * p);
    const tail = 46 + Math.max(0.15, MOUTH.bottomY - MOUTH.sideY);
    return [
      `M ${fmt(cx - w)} ${fmt(cy)}`,
      `C ${fmt(cx - w * 0.82)} ${fmt(cy - h)} ${fmt(cx + w * 0.82)} ${fmt(cy - h)} ${fmt(cx + w)} ${fmt(cy)}`,
      `L ${fmt(cx + w * 1.28)} ${fmt(cy + tail)}`,
      `L ${fmt(cx - w * 1.28)} ${fmt(cy + tail)} Z`
    ].join(" ");
  }
  function applyMouthPose() {
    const interior = svg.querySelector("#mouth-interior-clipped");
    const lower = svg.querySelector("#mouth-lower-cavity-fill");
    const setAttr = (id, k, v) => { const n = svg.querySelector(`#${id}`); if (n) n.setAttribute(k, v); };
    setAttr("mouth-opening-clip-path", "d", mouthOpeningClipD());
    setAttr("mouth-door-clip-path", "d", mouthDoorClipD());
    setAttr("mouth-inner-shade", "d", mouthCavityD());
    setAttr("mouth-cavity-fill", "d", mouthCavityD());
    setAttr("mouth-lower-cavity-fill", "d", mouthLowerCavityD());
    if (interior) {
      interior.style.display = mouthProgress > 1 ? "" : "none";
      interior.setAttribute("opacity", fmt(0.72 + 0.28 * clamp(mouthProgress / 100, 0, 1)));
    }
    if (lower) lower.style.display = mouthProgress > 18 ? "" : "none";
  }

  // ── 视线喂点（alert 同款：阶跃喂终点，禁连续轨迹——连续喂=每帧重置插值=指数阻尼实测踩坑）──
  // 卡片在屏幕系头左上 = master 系 yaw+ / pitch-（与 alert 感叹号同象限，mini-idle 真机验证语义）
  const LOOK = { centerX: 187, centerY: 157, halfW: 150, halfH: 120 };
  function feedLook(lookAmount) {
    if (typeof window.__cloudlingSetPointer !== "function") return;
    const masterX = LOOK.centerX + state.lookYaw * lookAmount * LOOK.halfW;
    const masterY = LOOK.centerY - state.lookPitch * lookAmount * LOOK.halfH;
    const miniX = masterY - 43;
    const miniY = 417 - masterX;
    window.__cloudlingSetPointer({ x: miniX, y: miniY, inside: true });
  }

  // ── 彩屑（确定性 SPECS，无 random；绽放一次性，保持段不循环）──
  // 起点散布在头(107,230)与卡片之间的屏幕内区域，向外飘+旋转+淡出
  const CONFETTI_SPECS = [
    { x: 30,  y: 90,  dx: -26, dy: -30, rot: -12, drot: -70, c: "#f8aaa2", w: 7,   h: 4,   delay: 0    },
    { x: 150, y: 110, dx: 24,  dy: -34, rot: 18,  drot: 80,  c: "#a8cfe8", w: 6,   h: 3.6, delay: 0.04 },
    { x: 75,  y: 60,  dx: -8,  dy: -38, rot: 30,  drot: 55,  c: "#f6d98b", w: 7.5, h: 4,   delay: 0.08 },
    { x: 185, y: 170, dx: 30,  dy: -16, rot: -24, drot: -60, c: "#b5d9a8", w: 6,   h: 3.6, delay: 0.12 },
    { x: 12,  y: 170, dx: -28, dy: -10, rot: 8,   drot: 65,  c: "#a8cfe8", w: 6.5, h: 3.8, delay: 0.06 },
    { x: 120, y: 40,  dx: 12,  dy: -30, rot: -30, drot: -75, c: "#f8aaa2", w: 6,   h: 3.5, delay: 0.14 },
    { x: 165, y: 240, dx: 30,  dy: 10,  rot: 14,  drot: 58,  c: "#f6d98b", w: 7,   h: 4,   delay: 0.1  },
    { x: 48,  y: 250, dx: -24, dy: 16,  rot: -8,  drot: -52, c: "#b5d9a8", w: 6,   h: 3.5, delay: 0.16 }
  ];
  const CONFETTI_LIFE = 1.15;
  const confettiLayer = document.getElementById("happy-confetti-layer");
  function renderConfetti(t, tBloom) {
    if (t < tBloom || t > tBloom + CONFETTI_LIFE + 0.3) { confettiLayer.innerHTML = ""; return; }
    let html = "";
    for (const s of CONFETTI_SPECS) {
      const lt = clamp((t - tBloom - s.delay) / CONFETTI_LIFE, 0, 1);
      if (lt <= 0 || lt >= 1) continue;
      const e = easeOutCubic(lt);
      const x = s.x + s.dx * e;
      const y = s.y + s.dy * e;
      const rot = s.rot + s.drot * lt;
      const op = smoothRange(0, 0.12, lt) * (1 - smoothRange(0.62, 1, lt));
      if (op < 0.02) continue;
      html += `<rect x="${fmt(-s.w / 2)}" y="${fmt(-s.h / 2)}" width="${fmt(s.w)}" height="${fmt(s.h)}" rx="1.6" fill="${s.c}" opacity="${fmt(op)}" transform="translate(${fmt(x)} ${fmt(y)}) rotate(${fmt(rot)})"/>`;
    }
    confettiLayer.innerHTML = html;
  }

  // ── 星星 twinkle（主线 bg-star/glasses-star 参数：base+alpha*sin(speed)）──
  const STAR_SPECS = [
    { id: "happy-star-a", x: 36, y: 24, scale: 0.95, offset: 0.08, speed: 0.62, base: 0.32, alpha: 0.5 },
    { id: "happy-star-b", x: 176, y: 64, scale: 1.0, offset: 0.42, speed: 0.58, base: 0.26, alpha: 0.46 },
    { id: "happy-glasses-star", x: 112, y: 151, scale: 1.2, offset: 0.14, speed: 1.15, base: 0.62, alpha: 0.38 }
  ];
  function renderStars(t, tBloom) {
    for (const s of STAR_SPECS) {
      const node = svg.querySelector(`#${s.id}`);
      if (!node) continue;
      const ramp = smoothRange(tBloom + 0.05, tBloom + 0.45, t);
      if (ramp <= 0.01) { node.setAttribute("opacity", "0"); continue; }
      const tw = s.base + s.alpha * (0.5 + 0.5 * Math.sin(2 * Math.PI * s.speed * (t - tBloom) + s.offset * 6.283));
      const popScale = lerp(0.55, 1, easeOutBack(ramp));
      node.setAttribute("opacity", fmt(clamp(tw, 0, 1) * ramp));
      node.setAttribute("transform", `translate(${fmt(s.x)} ${fmt(s.y)}) scale(${fmt(s.scale * popScale)})`);
    }
  }

  // ── 勾描画（dasharray/dashoffset；落定时卡片轻点头「咔哒」）──
  const tickEls = [1, 2, 3].map((i) => svg.querySelector(`#board-tick-${i}`));
  const tickLens = tickEls.map((p) => p.getTotalLength());
  const doneLen = svg.querySelector("#board-done-main").getTotalLength();
  function applyTicks(t, tl) {
    const starts = [tl.tick1, tl.tick2, tl.tick3];
    let kick = 0;
    for (let i = 0; i < 3; i += 1) {
      const p = clamp((t - starts[i]) / state.tickDur, 0, 1);
      const len = tickLens[i];
      tickEls[i].setAttribute("stroke", CHECK_PALETTES[state.checkPalette].color);
      if (p <= 0) {
        tickEls[i].setAttribute("stroke-dasharray", `0 ${fmt(len + 4)}`);
        continue;
      }
      tickEls[i].setAttribute("stroke-dasharray", `${fmt(len * p)} ${fmt(len + 4)}`);
      // 落定瞬间「咔哒」：小而短的 sin 脉冲，避免板子像被硬拽一下。
      const age = t - (starts[i] + state.tickDur);
      if (p >= 1 && age >= 0 && age <= 0.22) {
        const q = age / 0.22;
        const k = Math.sin(Math.PI * q) * (1 - q * 0.35);
        kick = Math.max(kick, k);
      }
    }
    return {
      dy: kick * state.tickKick,
      rot: -kick * state.tickRotKick
    };
  }

  // ── 每帧 ──
  let t0 = performance.now();
  let bloomedOnce = false;
  function frame(now) {
    const t = (now - t0) / 1000 * state.speed;
    const tl = timeline();

    // 卡片：首帧完整在场，轻浮动贯穿；大绿勾完成后才加入微呼吸。
    const floatDy = state.boardFloat * Math.sin(2 * Math.PI * t / 3.2);
    const floatRot = state.boardSwing * Math.sin(2 * Math.PI * t / 3.7 + 0.55);
    const introShakeRamp = 1 - smoothRange(0, 0.96, t);
    const introShake = state.boardIntroShake * introShakeRamp * Math.sin(2 * Math.PI * t / 0.34 + 1.15);
    const introDy = state.boardIntroShake * introShakeRamp * 0.24 * Math.sin(2 * Math.PI * t / 0.21 + 0.25);
    const tickMotion = applyTicks(t, tl);
    const postCheckAge = t - tl.tSee;
    const postCheckRamp = postCheckAge > 0 ? 1 - smoothRange(0, 1.35, postCheckAge) : 0;
    const postCheckWave = Math.sin(2 * Math.PI * postCheckAge / 0.34 + 0.3);
    const postCheckX = state.boardPostSway * postCheckRamp * postCheckWave;
    const postCheckRot = state.boardPostSway * 0.18 * postCheckRamp * Math.sin(2 * Math.PI * postCheckAge / 0.34 + 1.2);
    const breathStart = tl.tMorph + 0.34;
    const breathRamp = smoothRange(breathStart, breathStart + 0.5, t);
    const breathWave = Math.sin(2 * Math.PI * (t - breathStart) / 2.7);
    const boardBreath = 1 + breathRamp * state.boardBreathScale * breathWave;
    const breathRot = breathRamp * 0.45 * Math.sin(2 * Math.PI * (t - breathStart) / 2.7 + 1.2);
    const bx = state.boardX + postCheckX;
    const by = state.boardY + floatDy + introDy + tickMotion.dy;
    const bRot = state.boardRot + introShake + floatRot + tickMotion.rot + postCheckRot + breathRot;
    setT("happy-board", `translate(${fmt(bx)} ${fmt(by)}) rotate(${fmt(bRot)}) scale(${fmt(state.boardScale * boardBreath)})`);
    const boardNode = svg.querySelector("#happy-board");
    boardNode.setAttribute("opacity", "1");

    // 清单结算变身（鹿鹿口径，只动板）：tMorph 起条目+三勾淡出，纸上大绿勾描画+微弹
    const morphFade = 1 - smoothRange(tl.tMorph, tl.tMorph + 0.12, t);
    svg.querySelector("#board-rows").setAttribute("opacity", fmt(morphFade));
    svg.querySelector("#board-ticks").setAttribute("opacity", fmt(morphFade));
    const doneNode = svg.querySelector("#board-done");
    const doneDraw = smoothRange(tl.tMorph + 0.06, tl.tMorph + 0.28, t);
    const doneColor = DONE_PALETTES[state.donePalette].color;
    const donePop = lerp(0.7, 1, easeOutBack(smoothRange(tl.tMorph + 0.06, tl.tMorph + 0.34, t)));
    doneNode.setAttribute("opacity", fmt(doneDraw > 0 ? 1 : 0));
    doneNode.setAttribute("transform", `scale(${fmt(donePop)})`);
    ["board-done-under", "board-done-main"].forEach((id, i) => {
      const p = svg.querySelector(`#${id}`);
      p.setAttribute("stroke", doneColor);
      p.setAttribute("stroke-width", fmt(state.doneStroke + (i === 0 ? 5 : 0)));
      p.setAttribute("stroke-dasharray", `${fmt(doneLen * doneDraw)} ${fmt(doneLen + 4)}`);
    });

    // 视线：tLook 阶跃看卡片，tBack 阶跃回正（恒定目标不重置插值，EPS 守卫在引擎里）
    const lookAmount = (t >= tl.tLook && t < tl.tBack) ? 1 : 0;
    feedLook(lookAmount);

    // 绽放：开心嘴 0→mouthOpenMax（主线定稿几何）；保持段叠脉动
    const bloomT = smoothRange(tl.tBloom, tl.tBloom + state.bloomDur, t);
    mouthProgress = state.mouthOpenMax * bloomT;
    mouthPulseT = 0.5 + 0.5 * Math.sin(2 * Math.PI * (t - tl.holdStart) / 3.6 - Math.PI / 2);
    if (t < tl.holdStart) mouthPulseT *= smoothRange(tl.tBack, tl.holdStart, t);
    applyMouthPose();

    // 笑拱眉：主线 BROW_OFFSET (0,-3) 渐进切入（browLift 滑块）
    const browDy = -state.browLift * bloomT;
    const browT = Math.abs(browDy) > 0.02 ? `translate(0 ${fmt(browDy)})` : "";
    setT("brows", browT);

    // 呆毛：重力 -32 → 绽放雀跃至 tuftPerk；保持段错相轻飘
    const perk = smoothRange(tl.tBloom, tl.tBloom + 0.25, t);
    const floatRamp = smoothRange(tl.holdStart, tl.holdStart + 0.3, t);
    const fl = Math.sin(2 * Math.PI * 0.8 * (t - tl.holdStart)) * state.tuftFloat * floatRamp;
    const fr = Math.sin(2 * Math.PI * 0.8 * (t - tl.holdStart) + 0.9) * state.tuftFloat * floatRamp;
    const tuftBase = lerp(-32, state.tuftPerk, perk);
    setT("left-tuft", `rotate(${fmt(tuftBase + fl)} 182 49)`);
    setT("right-tuft", `rotate(${fmt(tuftBase + fr)} 200 50)`);

    // 领带微摆 wrapper（定稿串不碰；sleep 先例口径，绕领结中心母版系 (186.5,279)）
    const tieRamp = smoothRange(tl.holdStart, tl.holdStart + 0.5, t);
    const tieA = state.tieSway * Math.sin(2 * Math.PI * (t - tl.holdStart) / 4) * tieRamp;
    setT("happy-tie-sway", Math.abs(tieA) > 0.02 ? `rotate(${fmt(tieA)} 186.5 279)` : "");

    // 彩屑 + 星星
    renderConfetti(t, tl.tBloom);
    renderStars(t, tl.tBloom);

    if (t >= tl.tBloom && !bloomedOnce) bloomedOnce = true;

    // tuner 看片便利：保持段播够 4.5s 重播（导出资产不带）
    if (autoLoop && t >= tl.holdStart + 4.5) resetPlayback();

    refreshJson(t, tl);
    requestAnimationFrame(frame);
  }

  function resetPlayback() {
    t0 = performance.now();
    bloomedOnce = false;
    confettiLayer.innerHTML = "";
    feedLook(0);
  }

  function refreshJson() {} // 面板已剥离(导出无 tuner)

  // 验证钩子（headless 断言用）+ demo 重播接口（alert __miniAlert.replay 先例）
  window.__happyDebug = { state, timeline, replay: resetPlayback, get mouthProgress() { return mouthProgress; } };

  installMouthRig();
  applyTicks(-1, timeline());
  requestAnimationFrame(frame);
})();
